/**
 * Injects the compiled CSS into the DOM as a <style> tag
 * This must be called BEFORE React renders to avoid unstyled content flashing
 */
export function injectStyles(): void {
  // Prevent duplicate injection
  if (document.getElementById('synthra-compiled-styles')) {
    return;
  }

  // Create style element
  const styleElement = document.createElement('style');
  styleElement.id = 'synthra-compiled-styles';
  styleElement.type = 'text/css';
  styleElement.textContent = COMPILED_STYLES;

  // Inject into document head
  document.head.appendChild(styleElement);

  // Log for debugging
  console.log('[Synthra] CSS injection complete - compiled styles loaded');
}
